CREATE TABLE public.custom_courses (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT NOT NULL, description TEXT NOT NULL, color TEXT NOT NULL, emoji TEXT NOT NULL, locked BOOLEAN DEFAULT false, created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL, created_by UUID REFERENCES public.profiles(id) ON DELETE SET NULL); CREATE TABLE public.custom_lessons (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), course_id UUID REFERENCES public.custom_courses(id) ON DELETE CASCADE, title TEXT NOT NULL, subtitle TEXT NOT NULL, icon TEXT NOT NULL, type TEXT NOT NULL, time_limit_sec INTEGER, flashcards JSONB DEFAULT '[]'::jsonb, quiz JSONB DEFAULT '[]'::jsonb, pairs JSONB DEFAULT '[]'::jsonb, cloze JSONB DEFAULT '[]'::jsonb, legacy_cloze JSONB, created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL, created_by UUID REFERENCES public.profiles(id) ON DELETE SET NULL); ALTER TABLE public.custom_courses ENABLE ROW LEVEL SECURITY; ALTER TABLE public.custom_lessons ENABLE ROW LEVEL SECURITY; CREATE POLICY Allow public read custom_courses ON public.custom_courses FOR SELECT USING (true); CREATE POLICY Allow public read custom_lessons ON public.custom_lessons FOR SELECT USING (true); CREATE POLICY Allow admin all custom_courses ON public.custom_courses FOR ALL USING ((SELECT role FROM public.profiles WHERE id = auth.uid()) = 'admin'); CREATE POLICY Allow admin all custom_lessons ON public.custom_lessons FOR ALL USING ((SELECT role FROM public.profiles WHERE id = auth.uid()) = 'admin');
